class Solution:
    def uniqueXorTriplets(self, nums):
        pair = set()
        for a in nums:
            for b in nums:
                pair.add(a ^ b)
        res = set()
        for p in pair:
            for c in nums:
                res.add(p ^ c)
        return len(res)

